def binary_search_iterative(arr, target):
    """
    Performs binary search iteratively on a sorted array.
    """
    low = 0
    high = len(arr) - 1

    while low <= high:
        mid = (low + high) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            low = mid + 1
        else:
            high = mid - 1
    return -1

def binary_search_recursive(arr, target):
    """
    Performs binary search recursively on a sorted array.
    """
    def _binary_search_recursive_helper(arr, target, low, high):
        if low > high:
            return -1

        mid = (low + high) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            return _binary_search_recursive_helper(arr, target, mid + 1, high)
        else:
            return _binary_search_recursive_helper(arr, target, low, mid - 1)

    return _binary_search_recursive_helper(arr, target, 0, len(arr) - 1)
